#include <stdio.h>
#include <string.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        char line[2000];
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0';
        char *words[20];
        int wcnt = 0;
        char *token = strtok(line, " ");
        while (token && wcnt < 20) {
            words[wcnt++] = token;
            token = strtok(NULL, " ");
        }
        char letterLine[10];
        if (!fgets(letterLine, sizeof(letterLine), stdin)) break;
        char letter = letterLine[0];
        printf("[");
        int first = 1;
        for (int i = 0; i < wcnt; ++i) {
            if (strchr(words[i], letter)) {
                if (!first) printf(", ");
                printf("'%s'", words[i]);
                first = 0;
            }
        }
        printf("]\n");
    }
    return 0;
}

