    int T;
    if (!(cin >> T)) return 0;
    string dummy;
    getline(cin, dummy); // consume endline after T
    for (int tc = 0; tc < T; ++tc) {
        string wordsLine;
        getline(cin, wordsLine);
        string letterLine;
        getline(cin, letterLine);
        char letter = letterLine[0];
        vector<string> words;
        stringstream ss(wordsLine);
        string w;
        while (ss >> w) words.push_back(w);
        cout << "[";
        bool first = true;
        for (const string &word : words) {
            if (word.find(letter) != string::npos) {
                if (!first) cout << ", ";
                cout << "'" << word << "'";
                first = false;
            }
        }
        cout << "]\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String wordsLine = br.readLine();
            String letterLine = br.readLine();
            char letter = letterLine.charAt(0);
            String[] words = wordsLine.trim().split(" ");
            out.append('[');
            boolean first = true;
            for (String w : words) {
                if (w.indexOf(letter) >= 0) {
                    if (!first) out.append(", ");
                    out.append('\'').append(w).append('\'');
                    first = false;
                }
            }
            out.append(']').append('\n');
        }
        System.out.print(out.toString());
    }
}

code.Python3:
import sys

def filter_words(words, letter):
    return list(filter(lambda w: letter in w, words))

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out_lines = []
    for _ in range(t):
        words = data[idx].split()
        idx += 1
        letter = data[idx].strip()
        idx += 1
        result = filter_words(words, letter)
        out_lines.append(str(result))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

