  const words = lines[idx].trim().split(/\s+/);
  idx++;
  const letter = lines[idx].trim()[0];
  idx++;
  const filtered = words.filter(w => w.includes(letter));
  const formatted = '[' + filtered.map(w => `'${w}'`).join(', ') + ']';
  outputs.push(formatted);
}
